function sliderStockInit(){function e(){let e=window.innerWidth,t=document.querySelector(".stocks-slider__wrapper");if(e>1024){let e=t.clientWidth/(1344/441)+"px";t.style.height=e<323?"323px":e}else if(e>800){let e=t.clientWidth/(1024/371)+"px";t.style.height=e<323?"323px":e}else{let e=t.clientWidth/(1024/261)+"px";t.style.height=e<261?"261px":e}}window.addEventListener("DOMContentLoaded",e),window.addEventListener("load",e),window.addEventListener("resize",e)}sliderStockInit(),window.sliderStockInitGlobal=function(){sliderStockInit()};